+    #[cfg(unix)]
+    #[test]
+    fn drop_clears_global_even_with_nonzero_mask() {
+        let _g = TEST_LOCK.lock().unwrap();
+        let original = unsafe { umask(0o123) };
+
+        {
+            let _saver = UmaskSaver::new();
+            assert_eq!(UmaskSaver::saved_umask(), Some(0o123));
